extends Control

# Client script handling Login, Register & Chat UI
var peer = ENetMultiplayerPeer.new()
var PORT = 8080
var IP_ADDRESS = "127.0.0.1"

enum ChatMode { PUBLIC, PRIVATE }
var current_mode = ChatMode.PUBLIC
var current_receiver = ""
var username = ""

@onready var login_panel = $LoginPanel
@onready var chat_panel = $ChatPanel
@onready var chat_history = $ChatPanel/VBoxContainer/HistoryText
@onready var message_input = $ChatPanel/VBoxContainer/HBoxContainer/MessageInput
@onready var target_input = $ChatPanel/VBoxContainer/HBoxContainer/TargetInput
@onready var usr_input = $LoginPanel/VBox/UserInput
@onready var pwd_input = $LoginPanel/VBox/PwdInput
@onready var email_input = $LoginPanel/VBox/EmailInput
@onready var status_label = $LoginPanel/VBox/Label

func _ready():
    chat_panel.visible = false
    login_panel.visible = true

    # Connect to the Godot server as soon as the client opens
    var err = peer.create_client(IP_ADDRESS, PORT)
    if err == OK:
        multiplayer.multiplayer_peer = peer
    else:
        status_label.text = "Error: Cannot start ENet client"

    multiplayer.connected_to_server.connect(_on_connected)
    multiplayer.connection_failed.connect(_on_connection_error)
    multiplayer.server_disconnected.connect(_on_connection_error)

func _on_connected():
    status_label.text = "Connected to Server. Please Login."

func _on_connection_error():
    status_label.text = "Lost connection to Server!"

func _on_register_pressed():
    if multiplayer.multiplayer_peer.get_connection_status() != MultiplayerPeer.CONNECTION_CONNECTED:
        status_label.text = "Error: Not connected to Godot Server!"
        return

    status_label.text = "Registering..."
    rpc_id(1, "register_user", usr_input.text, pwd_input.text, email_input.text)

func _on_login_pressed():
    if multiplayer.multiplayer_peer.get_connection_status() != MultiplayerPeer.CONNECTION_CONNECTED:
        status_label.text = "Error: Not connected to Godot Server!"
        return

    status_label.text = "Logging in..."
    rpc_id(1, "login_user", usr_input.text, pwd_input.text)
    username = usr_input.text

@rpc("any_peer", "call_remote")
func auth_response(success: bool, msg: String):
    print(msg)
    if success:
        login_panel.visible = false
        chat_panel.visible = true
    else:
        status_label.text = "Failed: " + msg

func _on_send_pressed():
    var type = "text"
    var content = message_input.text
    var target = target_input.text

    if target == "":
        current_mode = ChatMode.PUBLIC
        rpc_id(1, "send_message", content, type, "")
    else:
        current_mode = ChatMode.PRIVATE
        rpc_id(1, "send_message", content, type, target)

    chat_history.text += "[You]: " + content + "\n"
    message_input.text = ""

@rpc("any_peer", "call_remote")
func receive_message(sender: String, content: String, type: String, is_private: bool):
    var prefix = "[Private from " + sender + "]: " if is_private else "[" + sender + "]: "
    chat_history.text += prefix + content + "\n"

@rpc("any_peer", "call_remote")
func update_status(status: String):
    pass

# --- RPC STUBS FOR SERVER ---
@rpc("any_peer", "call_remote") func register_user(_u, _p, _e): pass
@rpc("any_peer", "call_remote") func login_user(_u, _p): pass
@rpc("any_peer", "call_remote") func send_message(_c, _t, _tg): pass

extends Control

# 客户端脚本，用于处理登录、注册和聊天界面
var peer = ENetMultiplayerPeer.new() # 创建一个 ENet 网络节点实例
var PORT = 8080 # 服务器端口
var IP_ADDRESS = "127.0.0.1" # 服务器的 IP 地址

# 定义聊天模式枚举：公开和私聊
enum ChatMode { PUBLIC, PRIVATE }
var current_mode = ChatMode.PUBLIC # 当前的聊天模式
var current_receiver = "" # 当前私聊的接收者
var username = "" # 当前用户的用户名

# 存储各种聊天历史，空字符串代表大厅
var chat_histories = {"": ""} 

# 获取 UI 节点的引用
@onready var login_panel = $LoginPanel # 登录面板
@onready var chat_panel = $ChatPanel # 聊天面板
@onready var contact_list = $ChatPanel/ChatLayout/Sidebar/ContactList # 联系人列表
@onready var new_contact_input = $ChatPanel/ChatLayout/Sidebar/AddContactBox/NewContactInput # 新联系人输入框
@onready var current_chat_label = $ChatPanel/ChatLayout/ChatArea/CurrentChatLabel # 当前聊天频道名称
@onready var chat_history = $ChatPanel/ChatLayout/ChatArea/HistoryText # 聊天记录文本框
@onready var message_input = $ChatPanel/ChatLayout/ChatArea/InputLayout/MessageInput # 消息输入框
@onready var usr_input = $LoginPanel/VBox/UserInput # 用户名输入框
@onready var pwd_input = $LoginPanel/VBox/PwdInput # 密码输入框
@onready var email_input = $LoginPanel/VBox/EmailInput # 邮箱输入框
@onready var status_label = $LoginPanel/VBox/Label # 状态标签（显示登录/连接状态）

func _ready():
    # 初始状态隐藏聊天面板，显示登录面板
    chat_panel.visible = false
    login_panel.visible = true

    # 客户端一打开就连接 Godot 服务器
    var err = peer.create_client(IP_ADDRESS, PORT)
    if err == OK:
        multiplayer.multiplayer_peer = peer # 将当前的网络节点设置为刚才创建的客户端节点
    else:
        status_label.text = "Error: Cannot start ENet client" # 无法启动客户端时报错

    # 连接网络信号以响应连接成功和断开事件
    multiplayer.connected_to_server.connect(_on_connected)
    multiplayer.connection_failed.connect(_on_connection_error)
    multiplayer.server_disconnected.connect(_on_connection_error)

    # 绑定回车键发送消息
    message_input.text_submitted.connect(_on_message_input_text_submitted)

# 连接服务器成功时的回调
func _on_connected():
    status_label.text = "Connected to Server. Please Login."

# 连接服务器失败或断开连接时的回调
func _on_connection_error():
    status_label.text = "Lost connection to Server!"

# 点击注册按钮时的回调
func _on_register_pressed():
    # 检查是否已连接到服务器
    if multiplayer.multiplayer_peer.get_connection_status() != MultiplayerPeer.CONNECTION_CONNECTED:
        status_label.text = "Error: Not connected to Godot Server!"
        return

    status_label.text = "Registering..." # 显示注册中
    # 发送注册请求到服务器（ID 为 1 代表服务器）
    rpc_id(1, "register_user", usr_input.text, pwd_input.text, email_input.text)

# 点击登录按钮时的回调
func _on_login_pressed():
    # 检查是否已连接到服务器
    if multiplayer.multiplayer_peer.get_connection_status() != MultiplayerPeer.CONNECTION_CONNECTED:
        status_label.text = "Error: Not connected to Godot Server!"
        return

    status_label.text = "Logging in..."  # 显示登录中
    # 发送登录请求到服务器
    rpc_id(1, "login_user", usr_input.text, pwd_input.text)
    username = usr_input.text # 保存当前尝试登录的用户名

# 接收服务器发回的认证响应
@rpc("any_peer", "call_remote")
func auth_response(success: bool, msg: String):
    print(msg)
    if success:
        # 登录成功，隐藏登录面板，显示聊天面板
        login_panel.visible = false
        chat_panel.visible = true

        # 登录成功后，清除旧数据
        contact_list.clear()
        contact_list.add_item("公共大厅")
        contact_list.select(0) # 默认选中第一项（公共大厅）
        chat_histories = {"": ""}
        current_receiver = ""
        current_mode = ChatMode.PUBLIC
        _update_chat_ui()
    else:
        # 登录失败，显示错误信息
        status_label.text = "Failed: " + msg

# 点击发送消息按钮时的回调
func _on_send_pressed():
    var type = "text" # 消息类型为普通文本
    var content = message_input.text # 获取输入的消息内容
    var target = current_receiver # 当前选中的对象

    # 消息为空则不发送
    if content.strip_edges() == "":
        return

    # 如果目标为空，则发送公开消息，否则发送私聊消息
    if target == "":
        current_mode = ChatMode.PUBLIC
        rpc_id(1, "send_message", content, type, "") # 向服务器发送广播消息
    else:
        current_mode = ChatMode.PRIVATE
        rpc_id(1, "send_message", content, type, target) # 向服务器发送私聊消息请求

    # 在本地聊天记录中追加自己发送的消息
    _append_chat_history(target, "[You]: " + content)
    message_input.text = "" # 清空输入框

# 输入框按下回车时的回调
func _on_message_input_text_submitted(_new_text: String):
    _on_send_pressed()

# 接收别人发来的消息
@rpc("any_peer", "call_remote")
func receive_message(sender: String, receiver: String, content: String, type: String, is_private: bool):
    # 如果是公聊，把它放在公共大厅；
    # 如果是私聊，需判断这个消息是我发给别人的，还是别人发给我的，以此来决定将它放在哪个联系人的历史里
    var target_channel = ""
    if is_private:
        # 如果发送者是我自己，说明这是从历史记录拉取出来的我发给别人的消息
        if sender == username:
            target_channel = receiver # 发给别人，放在别人的聊天窗口
        else:
            target_channel = sender # 别人发给我，放在别人的聊天窗口

    # 统一前缀格式为 [名字]: ，不再区分公屏还是私聊
    var prefix = "[" + sender + "]: "

    # 如果是我发出的话（比如加载历史记录时），统一显示 [You]: 
    if sender == username:
        prefix = "[You]: "

    # 将消息追加到对应聊天记录
    _append_chat_history(target_channel, prefix + content)

# 封装好的添加聊天记录函数
func _append_chat_history(channel: String, text: String):
    # 判断该联系人是否已在我方列表内
    if not chat_histories.has(channel):
        chat_histories[channel] = ""
        if channel != "":
            contact_list.add_item(channel)

    # 拼接文本
    if chat_histories[channel] != "":
        chat_histories[channel] += "\n"
    chat_histories[channel] += text

    # 若正好是当前停留的窗口，顺便刷新 UI 文本框
    if current_receiver == channel:
        chat_history.text = chat_histories[channel]
        chat_history.scroll_vertical = chat_history.get_line_count()

# 联系人被选中时的回调
func _on_contact_selected(index: int):
    # index 0 固定为“公共大厅”
    if index == 0:
        current_receiver = ""
        current_mode = ChatMode.PUBLIC
        current_chat_label.text = "公共大厅" # 更新聊天界面的标题
    else:
        current_receiver = contact_list.get_item_text(index)
        current_mode = ChatMode.PRIVATE
        current_chat_label.text = "与 " + current_receiver + " 私聊中" # 提示当前处于私聊

    # 刷新聊天区显示的内容
    _update_chat_ui()

# 更新聊天区域显示
func _update_chat_ui():
    # 如果没有该联系人的聊天记录，初始化为空
    if not chat_histories.has(current_receiver):
        chat_histories[current_receiver] = ""

    chat_history.text = chat_histories[current_receiver] # 将记录文本显示在UI上
    chat_history.scroll_vertical = chat_history.get_line_count() # 滚动到最底部

# 点击添加联系人按钮
func _on_add_contact_pressed():
    var new_contact = new_contact_input.text.strip_edges() # 去除前后多余空格

    # 防止空内容或添加自己为联系人
    if new_contact == "" or new_contact == username:
        return

    # 如果列表里还没有这个人，将其加入联系人列表
    if not chat_histories.has(new_contact):
        chat_histories[new_contact] = ""
        contact_list.add_item(new_contact)
        new_contact_input.text = "" # 添加后清空输入框

# 接收来自服务器的消息状态更新（例如：delivered）
@rpc("any_peer", "call_remote")
func update_status(status: String):
    pass

# --- RPC STUBS FOR SERVER ---
# 这些是服务器端接收函数的存根（Stub），为了让客户端通过 rpc_id 能够查找到相应的方法名
@rpc("any_peer", "call_remote") func register_user(_u, _p, _e): pass # 注册方法
@rpc("any_peer", "call_remote") func login_user(_u, _p): pass # 登录方法
@rpc("any_peer", "call_remote") func send_message(_c, _t, _tg): pass # 发送消息方法

extends Control

# Server Script
var peer = ENetMultiplayerPeer.new()
var PORT = 8080
var PYTHON_API_URL = "http://127.0.0.1:5000/api/"

var connected_users = {} # client_id : username
var user_clients = {}    # username : client_id

func _ready():
    peer.create_server(PORT)
    multiplayer.multiplayer_peer = peer
    multiplayer.peer_connected.connect(_on_peer_connected)
    multiplayer.peer_disconnected.connect(_on_peer_disconnected)
    print("Server started on port ", PORT)

# Helper function to send async HTTP request
func _send_http_request(endpoint: String, payload: Dictionary) -> Dictionary:
    var http_request = HTTPRequest.new()
    add_child(http_request)
    var json = JSON.stringify(payload)
    var headers = ["Content-Type: application/json"]
    http_request.request(PYTHON_API_URL + endpoint, headers, HTTPClient.METHOD_POST, json)

    var response = await http_request.request_completed
    var result = response[0]
    var response_code = response[1]
    var headers_resp = response[2]
    var body = response[3]

    http_request.queue_free()

    if response_code == 200:
        var json_response = JSON.parse_string(body.get_string_from_utf8())
        if typeof(json_response) == TYPE_DICTIONARY:
            return json_response

    return {"success": false, "msg": "HTTP request failed"}


func _on_peer_connected(id):
    print("Peer connected: ", id)

func _on_peer_disconnected(id):
    if connected_users.has(id):
        var uname = connected_users[id]
        user_clients.erase(uname)
        connected_users.erase(id)
    print("Peer disconnected: ", id)

@rpc("any_peer", "call_remote")
func register_user(username, password, email):
    var client_id = multiplayer.get_remote_sender_id()
    var response = await _send_http_request("register", {"username": username, "password": password, "email": email})

    if response.get("success", false):
        rpc_id(client_id, "auth_response", true, "Register successful")
    else:
        var msg = response.get("msg", "Registration failed")
        rpc_id(client_id, "auth_response", false, msg)

@rpc("any_peer", "call_remote")
func login_user(username, password):
    var client_id = multiplayer.get_remote_sender_id()
    var response = await _send_http_request("login", {"username": username, "password": password})

    if response.get("success", false):
        connected_users[client_id] = username
        user_clients[username] = client_id
        rpc_id(client_id, "auth_response", true, "Login successful")

        # Load history
        var history_response = await _send_http_request("get_history", {"username": username})
        if history_response.get("success", false):
            var history = history_response.get("history", [])
            for msg in history:
                var is_private = msg.receiver != ""
                rpc_id(client_id, "receive_message", msg.sender, msg.content, msg.type, is_private)
    else:
        rpc_id(client_id, "auth_response", false, response.get("msg", "Login failed"))

@rpc("any_peer", "call_remote")
func send_message(content, type, target):
    var sender_id = multiplayer.get_remote_sender_id()
    var sender_name = connected_users.get(sender_id, "Unknown")

    # Fire and forget save
    _send_http_request("save_message", {"sender": sender_name, "receiver": target, "content": content, "type": type})
    rpc_id(sender_id, "update_status", "delivered")

    if target == "": # Public
        for client in connected_users.keys():
            if client != sender_id:
                rpc_id(client, "receive_message", sender_name, content, type, false)
    else: # Private
        if user_clients.has(target):
            rpc_id(user_clients[target], "receive_message", sender_name, content, type, true)
            rpc_id(sender_id, "update_status", "read")

# --- RPC STUBS FOR CLIENT ---
@rpc("any_peer", "call_remote") func auth_response(_success, _msg): pass
@rpc("any_peer", "call_remote") func receive_message(_sender, _content, _type, _is_private): pass
@rpc("any_peer", "call_remote") func update_status(_status): pass

extends Control

# 服务器端脚本
var peer = ENetMultiplayerPeer.new() # 创建一个 ENet 网络节点实例作为服务器
var PORT = 8080 # 服务器监听的端口
var PYTHON_API_URL = "http://127.0.0.1:5000/api/" # 对应的 Python 后端 API 地址

var connected_users = {} # 存储映射：client_id(客户端ID) : username(用户名)
var user_clients = {}    # 存储映射：username(用户名) : client_id(客户端ID)

func _ready():
    peer.create_server(PORT) # 启动服务器，监听指定端口
    multiplayer.multiplayer_peer = peer # 设置当前网络节点为服务器节点
    multiplayer.peer_connected.connect(_on_peer_connected) # 连接客户端接入的信号
    multiplayer.peer_disconnected.connect(_on_peer_disconnected) # 连接客户端断开的信号
    print("Server started on port ", PORT)

# 辅助函数：发送异步 HTTP 请求给 Python 后端
func _send_http_request(endpoint: String, payload: Dictionary) -> Dictionary:
    var http_request = HTTPRequest.new() # 创建 HTTP 请求节点
    add_child(http_request) # 添加到场景树中
    var json = JSON.stringify(payload) # 将字典载荷转换为 JSON 字符串
    var headers = ["Content-Type: application/json"] # 设置请求头
    # 向指定端点发起 POST 请求
    http_request.request(PYTHON_API_URL + endpoint, headers, HTTPClient.METHOD_POST, json)

    var response = await http_request.request_completed # 等待请求完成
    var result = response[0]
    var response_code = response[1]
    var headers_resp = response[2]
    var body = response[3]

    http_request.queue_free() # 释放 HTTP 请求节点

    if response_code == 200:
        # 如果返回 200，则解析返回的 JSON 数据
        var json_response = JSON.parse_string(body.get_string_from_utf8())
        if typeof(json_response) == TYPE_DICTIONARY:
            return json_response

    return {"success": false, "msg": "HTTP request failed"} # 如果失败返回默认错误信息


# 当有客户端连接时回调
func _on_peer_connected(id):
    print("Peer connected: ", id)

# 当有客户端断开连接时回调
func _on_peer_disconnected(id):
    if connected_users.has(id):
        # 清除断开连接的用户在字典中的记录
        var uname = connected_users[id]
        user_clients.erase(uname)
        connected_users.erase(id)
    print("Peer disconnected: ", id)

# 处理客户端的注册请求
@rpc("any_peer", "call_remote")
func register_user(username, password, email):
    var client_id = multiplayer.get_remote_sender_id() # 获取发送请求的客户端 ID
    # 向后台发送注册的 HTTP 请求
    var response = await _send_http_request("register", {"username": username, "password": password, "email": email})

    if response.get("success", false):
        # 成功，告诉该客户端并发送认证响应
        rpc_id(client_id, "auth_response", true, "Register successful")
    else:
        # 失败，发送失败信息
        var msg = response.get("msg", "Registration failed")
        rpc_id(client_id, "auth_response", false, msg)

# 处理客户端的登录请求
@rpc("any_peer", "call_remote")
func login_user(username, password):
    var client_id = multiplayer.get_remote_sender_id() # 获取发送请求的客户端 ID
    # 向后台发送登录的 HTTP 请求
    var response = await _send_http_request("login", {"username": username, "password": password})

    if response.get("success", false):
        # 登录成功，把玩家添加到在线列表
        connected_users[client_id] = username
        user_clients[username] = client_id
        rpc_id(client_id, "auth_response", true, "Login successful") # 通知客户端登录成功

        # 向后台请求���天记录
        var history_response = await _send_http_request("get_history", {"username": username})
        if history_response.get("success", false):
            var history = history_response.get("history", [])
            for msg in history:
                # 判断是否是私聊
                var is_private = msg.receiver != ""
                # 把 sender 和 receiver 都传过去，方便客户端正确归类历史信息
                rpc_id(client_id, "receive_message", msg.sender, msg.receiver, msg.content, msg.type, is_private)
    else:
        # 登录失败，通知客户端
        rpc_id(client_id, "auth_response", false, response.get("msg", "Login failed"))

# 处理客户端的发送消息请求
@rpc("any_peer", "call_remote")
func send_message(content, type, target):
    var sender_id = multiplayer.get_remote_sender_id() # 获取发送请求的客户端 ID
    var sender_name = connected_users.get(sender_id, "Unknown") # 获取用户名

    # 将消息保存到后台数据库，无需等待响应
    _send_http_request("save_message", {"sender": sender_name, "receiver": target, "content": content, "type": type})
    rpc_id(sender_id, "update_status", "delivered") # 告诉发送者消息已投递

    if target == "": # 如果目标为空，视为公共消息（广播）
        for client in connected_users.keys():
            if client != sender_id: # 不要发给自己
                rpc_id(client, "receive_message", sender_name, "", content, type, false)
    else: # 否则是私下发送（私聊）
        if user_clients.has(target):
            # 发送给指定的用户
            rpc_id(user_clients[target], "receive_message", sender_name, target, content, type, true)
            rpc_id(sender_id, "update_status", "read") # 假设发过去以后算作已读

# --- RPC STUBS FOR CLIENT ---
# 这些是客户端接收函数的存根，为了让服务器通过 rpc_id 能够查找到相应的方法名
@rpc("any_peer", "call_remote") func auth_response(_success, _msg): pass # 认证响应
@rpc("any_peer", "call_remote") func receive_message(_sender, _receiver, _content, _type, _is_private): pass # 接收消息
@rpc("any_peer", "call_remote") func update_status(_status): pass # 更新发送状态

import os
from flask import Flask, request, jsonify
import mysql.connector
from datetime import datetime

app = Flask(__name__)

# Database configuration (adjust user and password to your local MySQL settings)
DB_CONFIG = {
    'host': '127.0.0.1',
    'user': 'root',
    'password': 'zlm258078', # PUT YOUR MYSQL PASSWORD HERE
    'database': 'chat_room',
    'autocommit': True
}

def get_db_connection():
    try:
        conn = mysql.connector.connect(**DB_CONFIG)
        return conn
    except mysql.connector.Error as err:
        print(f"Error connecting to MySQL: {err}")
        return None

@app.route('/api/register', methods=['POST'])
def register():
    data = request.json
    username = data.get('username')
    password = data.get('password') # In a real app, hash this!
    email = data.get('email')

    conn = get_db_connection()
    if not conn:
        return jsonify({'success': False, 'msg': 'Database connection error'})

    cursor = conn.cursor()
    try:
        cursor.execute("SELECT id FROM Users WHERE username = %s OR email = %s", (username, email))
        if cursor.fetchone():
            return jsonify({'success': False, 'msg': 'Username or email already exists'})

        cursor.execute(
            "INSERT INTO Users (username, password_hash, email) VALUES (%s, %s, %s)",
            (username, password, email)
        )
        return jsonify({'success': True, 'msg': 'User registered successfully'})
    except Exception as e:
        return jsonify({'success': False, 'msg': str(e)})
    finally:
        cursor.close()
        conn.close()

@app.route('/api/login', methods=['POST'])
def login():
    data = request.json
    username = data.get('username')
    password = data.get('password')

    conn = get_db_connection()
    if not conn:
        return jsonify({'success': False, 'msg': 'Database connection error'})

    cursor = conn.cursor(dictionary=True)
    try:
        cursor.execute("SELECT id, username FROM Users WHERE username = %s AND password_hash = %s", (username, password))
        user = cursor.fetchone()
        if user:
            return jsonify({'success': True, 'msg': 'Login successful', 'user_id': user['id']})
        else:
            return jsonify({'success': False, 'msg': 'Invalid credentials'})
    except Exception as e:
        return jsonify({'success': False, 'msg': str(e)})
    finally:
        cursor.close()
        conn.close()

@app.route('/api/save_message', methods=['POST'])
def save_message():
    data = request.json
    sender_name = data.get('sender')
    receiver_name = data.get('receiver')
    content = data.get('content')
    msg_type = data.get('type', 'text')

    conn = get_db_connection()
    if not conn:
        return jsonify({'success': False})

    cursor = conn.cursor(dictionary=True)
    try:
        cursor.execute("SELECT id FROM Users WHERE username = %s", (sender_name,))
        sender = cursor.fetchone()
        sender_id = sender['id'] if sender else None

        receiver_id = None
        if receiver_name:
            cursor.execute("SELECT id FROM Users WHERE username = %s", (receiver_name,))
            receiver = cursor.fetchone()
            if receiver:
                receiver_id = receiver['id']

        if not sender_id:
            return jsonify({'success': False, 'msg': 'Sender not found'})

        cursor.execute(
            "INSERT INTO Messages (sender_id, receiver_id, content, msg_type) VALUES (%s, %s, %s, %s)",
            (sender_id, receiver_id, content, msg_type)
        )
        return jsonify({'success': True})
    except Exception as e:
        return jsonify({'success': False, 'msg': str(e)})
    finally:
        cursor.close()
        conn.close()

@app.route('/api/get_history', methods=['POST'])
def get_history():
    data = request.json
    username = data.get('username')

    conn = get_db_connection()
    if not conn:
        return jsonify({'success': False, 'history': []})

    cursor = conn.cursor(dictionary=True)
    try:
        cursor.execute("SELECT id FROM Users WHERE username = %s", (username,))
        user = cursor.fetchone()
        user_id = user['id'] if user else None

        if not user_id:
            return jsonify({'success': False, 'history': []})

        query = """
            SELECT m.content, m.msg_type as type, s.username as sender, r.username as receiver
            FROM Messages m
            JOIN Users s ON m.sender_id = s.id
            LEFT JOIN Users r ON m.receiver_id = r.id
            WHERE m.receiver_id = %s OR m.receiver_id IS NULL OR m.sender_id = %s
            ORDER BY m.created_at ASC
        """
        cursor.execute(query, (user_id, user_id))
        history = cursor.fetchall()

        # Replace NULL receiver with empty string for Godot compatibility
        for msg in history:
            if not msg['receiver']:
                msg['receiver'] = ""

        return jsonify({'success': True, 'history': history})
    except Exception as e:
        return jsonify({'success': False, 'history': [], 'msg': str(e)})
    finally:
        cursor.close()
        conn.close()

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000)
